  ('pukao-e3452428-moex-00126', 'pukao-e3452428', 'pukao-e3452428-moex-114-d1a761c9', 'sub-pukao-e3452428-03', NULL, 'single_choice', '依國家賠償法規定，下列何種情形並不成立國家賠償責任？', '["職司道路養護之公務員故意怠於履行職務，長期無視道路特定坑洞之存在，致使機車騎士行經該路段滑 倒受傷", "員警進行夜間定時巡邏業務，因過失未留意燈號變換而誤闖紅燈，撞上依燈號指示左轉之民眾車輛", "因過去已有多起溺水意外，主管機關於開放水域設置禁止游泳之警示標語，人民仍執意下水而喪失生命", "高速公路交流道設計與建造有所缺失，匝道彎度明顯過大，導致民眾車輛翻覆而駕駛受傷"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "884c46aa9173", "answer_pdf_sha1": "bd41d588bfdd", "source_family": "moex-gov-tw", "moex": {"exam_code": "114080", "c": "402", "s": "0406", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "114", "exam_name": "114年公務人員高等考試三級考試暨普通考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
