  ('pukao-e3452428-moex-00130', 'pukao-e3452428', 'pukao-e3452428-moex-113-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '下列何者非屬我國現行實施地方自治之相關法規範依據？', '["省縣自治通則", "中華民國憲法增修條文", "財政收支劃分法", "地方制度法"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "6f3ffb0e7303", "answer_pdf_sha1": "79ae9d85eb3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "402", "s": "0307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL),
