  ('pukao-e3452428-moex-00134', 'pukao-e3452428', 'pukao-e3452428-moex-113-77777d6f', 'sub-pukao-e3452428-01', NULL, 'single_choice', '依司法院釋字第498號解釋意旨，關於立法院交通委員會邀請直轄市交通局長到會備詢，下列敘 述何者正確？', '["地方自治為憲法所保障之制度，立法院交通委員會不得邀請直轄市交通局長到會備詢", "除法律明定應到會備詢者外，直轄市交通局長得衡酌到會說明之必要性，決定是否到會", "直轄市交通局長若拒絕到會備詢，立法院得以此為由刪減對該直轄市之補助款預算", "直轄市交通局長若拒絕到會備詢，監察院得以此為由彈劾該交通局局長"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:21+00:00", "source_pdf_sha1": "6f3ffb0e7303", "answer_pdf_sha1": "79ae9d85eb3f", "source_family": "moex-gov-tw", "moex": {"exam_code": "113080", "c": "402", "s": "0307", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "地方自治概要", "year": "113", "exam_name": "113年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般民政"}'::jsonb, NULL)
